import React from 'react';
import { Outlet, Route } from 'react-router-dom';
import { connect } from 'react-redux';

import { onSnapshot, collection } from 'firebase/firestore';

import { convertCollectionsSnapshotToMap, db } from '../../firebase/firebase.utils';

import updateCollections from '../../redux/shop/shop.actions'

import CollectionsOverview from '../../components/collection-overview/collection-overview.component';
import CollectionPage from '../collection/collection.component';

class ShopPage extends React.Component {
    unsubscribeFromSnapshot = null;
    
    
    componentDidMount () {
        const { updateCollections } = this.props;
        const collectionRef = collection(db, "collections");

        this.unsubscribeFromSnapshotconst = onSnapshot(collectionRef, async (snapshot) => {
            const collectionMap = convertCollectionsSnapshotToMap(snapshot);
            console.log(collectionMap);
            updateCollections(collectionMap);
        });  
    }

    render() {
            return(
                <div className='shop-page'> 
                    <Route path="/"> <CollectionsOverview /> </Route>
                    <Route  path="/:collectionId" element={<CollectionPage />} />
                </div>
            )

    }
}

mapDispatchToProps = (dispatch) => ({
    shopActions: collectionMap => dispatch(updateCollections(collectionMap))
})
export default connect(null, mapDispatchToProps)(ShopPage);
